Provider component:
```typescript
// src/trpc/provider.tsx
'use client';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { httpBatchLink } from '@trpc/client';
import superjson from 'superjson';
import { useState } from 'react';
import { trpc } from './client';

function getBaseUrl() {
  if (typeof window !== 'undefined') return '';
  return `http://localhost:${process.env.PORT ?? 3000}`;
}

export function TRPCProvider({ children }: { children: React.ReactNode }) {
  const [queryClient] = useState(() => new QueryClient());
  const [trpcClient] = useState(() =>
    trpc.createClient({
      links: [
        httpBatchLink({
          url: `${getBaseUrl()}/api/trpc`,
          transformer: superjson,
        }),
      ],
    })
  );
  return (
    <trpc.Provider client={trpcClient} queryClient={queryClient}>
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    </trpc.Provider>
  );
}
```

### src/trpc/server.ts (update if stub exists)

Server-side caller for use in Server Components:

```typescript
import { createCallerFactory } from '@trpc/server';
import { createContext } from '@/server/context';
import { appRouter } from '@/server/root';

const createCaller = createCallerFactory(appRouter);

export const api = async () => {
  const ctx = await createContext();
  return createCaller(ctx);
};
```

Usage in Server Components:
```typescript
const caller = await api();
const data = await caller.student.someQuery();
```

### src/app/api/trpc/[trpc]/route.ts

```typescript
import { fetchRequestHandler } from '@trpc/server/adapters/fetch';
import { appRouter } from '@/server/root';
import { createContext } from '@/server/context';

const handler = (req: Request) =>
  fetchRequestHandler({
    endpoint: '/api/trpc',
    req,
    router: appRouter,
    createContext,
  });

export { handler as GET, handler as POST };
```

## Rules

- No `any` types
- TypeScript strict mode throughout
- superjson as transformer everywhere (client + server must match)
- All routers start empty — procedures added in Waves 3-7
- `roleProcedure` reads from `profiles` table via `ctx.db.query.profiles.findFirst()`
- Context must expose: `db`, `supabase`, `session`, `user`

## Acceptance gate

Run: `npm run typecheck` — must pass with zero errors.
Run: `npm run test` — must pass.

Then:
`git add src/server/ src/trpc/ src/app/api/trpc/`
`git commit -m "feat(trpc): wire root router, context, 6 role routers, server caller"`

Then open a PR to main.
